import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
});

// Add token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const authAPI = {
  login: (email: string, password: string) => api.post('/auth/login', { email, password }),
  register: (userData: any) => api.post('/auth/register', userData),
};

export const gamesAPI = {
  getGames: (params?: any) => api.get('/games', { params }),
  getGame: (id: string) => api.get(`/games/${id}`),
  createGame: (gameData: any) => api.post('/games', gameData),
  updateGame: (id: string, gameData: any) => api.put(`/games/${id}`, gameData),
  deleteGame: (id: string) => api.delete(`/games/${id}`),
};

export const ordersAPI = {
  createOrder: (orderData: any) => api.post('/orders', orderData),
  getMyOrders: () => api.get('/orders/my-orders'),
};

export const adminAPI = {
  getOrders: () => api.get('/admin/orders'),
  getGames: () => api.get('/admin/games'),
  getUsers: () => api.get('/admin/users'),
  updateOrderStatus: (id: string, status: string) => api.put(`/admin/orders/${id}/status`, { status }),
};

export const uploadAPI = {
  uploadImage: (file: File) => {
    const formData = new FormData();
    formData.append('image', file);
    return api.post('/upload/image', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
  },
  uploadImages: (files: File[]) => {
    const formData = new FormData();
    files.forEach((file) => {
      formData.append('images', file);
    });
    return api.post('/upload/images', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
  },
};

export default api;
